import React, { useRef, useState, useEffect } from 'react';
import { useNavigate, Link, useLocation } from 'react-router-dom';
import { FaSignOutAlt, FaHome, FaDatabase, FaUpload } from 'react-icons/fa';

const Header = ({ userInfo }) => {
  const navigate = useNavigate();
  const location = useLocation();

  const handleLogout = () => {
    localStorage.removeItem('token');
    localStorage.removeItem('userInfo');
    navigate('/login');
  };

  // Helper to check if a path is active
  const isActive = (path) => location.pathname === path;

  // Common nav link style
  const navLinkBase = {
    textDecoration: 'none',
    color: '#0078d4',
    fontSize: '0.95rem',
    fontWeight: 600,
    display: 'flex',
    alignItems: 'center',
    padding: '8px 16px',
    borderRadius: '20px',
    transition: 'all 0.3s',
    background: 'linear-gradient(90deg, #e3f0ff 0%, #f7fafd 100%)',
    marginRight: '10px',
    boxShadow: '0 2px 8px #0078d411',
    border: '1px solid #e0e6ed',
  };
  const navLinkActive = {
    background: 'linear-gradient(90deg, #0078d4 0%, #d60000 100%)',
    color: '#fff',
    boxShadow: '0 2px 8px #d6000044',
    border: '1.5px solid #0078d4',
  };

  // Dropdown state for profile menu
  const [dropdownOpen, setDropdownOpen] = useState(false);
  const dropdownRef = useRef(null);

  // Add a ref to the profile button to match dropdown width
  const profileBtnRef = useRef(null);
  const [profileBtnWidth, setProfileBtnWidth] = useState(0);
  useEffect(() => {
    if (profileBtnRef.current) {
      setProfileBtnWidth(profileBtnRef.current.offsetWidth);
    }
  }, [dropdownOpen, userInfo?.Username]);

  // Close dropdown on outside click
  useEffect(() => {
    if (!dropdownOpen) return;
    function handleClick(e) {
      if (dropdownRef.current && !dropdownRef.current.contains(e.target)) {
        setDropdownOpen(false);
      }
    }
    document.addEventListener('mousedown', handleClick);
    return () => document.removeEventListener('mousedown', handleClick);
  }, [dropdownOpen]);

  // Keyboard accessibility (ESC to close)
  useEffect(() => {
    if (!dropdownOpen) return;
    function handleKey(e) {
      if (e.key === 'Escape') setDropdownOpen(false);
    }
    document.addEventListener('keydown', handleKey);
    return () => document.removeEventListener('keydown', handleKey);
  }, [dropdownOpen]);

  // Add live current time state
  const [currentTime, setCurrentTime] = useState(() => {
    const d = new Date();
    const pad = n => n.toString().padStart(2, '0');
    return `${pad(d.getDate())}/${pad(d.getMonth() + 1)}/${d.getFullYear()},  ${pad(d.getHours())}:${pad(d.getMinutes())}:${pad(d.getSeconds())}`;
  });
  useEffect(() => {
    const interval = setInterval(() => {
      const d = new Date();
      const pad = n => n.toString().padStart(2, '0');
      setCurrentTime(`${pad(d.getDate())}/${pad(d.getMonth() + 1)}/${d.getFullYear()},  ${pad(d.getHours())}:${pad(d.getMinutes())}:${pad(d.getSeconds())}`);
    }, 1000);
    return () => clearInterval(interval);
  }, []);

  // Last login time state
  const [lastLoginTime, setLastLoginTime] = useState('');
  useEffect(() => {
    setLastLoginTime(localStorage.getItem('lastLoginTime') || '');
  }, [dropdownOpen]);

  const navItems = [
    {
      to: '/dashboard',
      icon: <FaHome className="me-2" />,
      text: 'Dashboard',
      gradient: 'linear-gradient(135deg, #4A00E0, #8E2DE2)'
    },
    {
      to: '/rfid-transactions',
      icon: <FaDatabase className="me-2" />,
      text: 'RFID Transactions',
      gradient: 'linear-gradient(135deg, #06beb6, #48b1bf)'
    },
    {
      to: '/upload-rfid',
      icon: <FaUpload className="me-2" />,
      text: 'Upload RFID',
      gradient: 'linear-gradient(135deg, #d60000, #ff0000)'
    }
  ];

  return (
    <header style={{
      background: 'linear-gradient(90deg, #fff 0%, #fafdff 60%, #e3f0ff 90%, #fbeaec 100%)',
      boxShadow: '0 2px 10px rgba(0, 120, 212, 0.07)',
      borderBottom: '1.5px solid #e0e6ed',
      fontFamily: 'Poppins, Inter, sans-serif',
      fontWeight: 500,
      letterSpacing: 0.1,
      zIndex: 100,
      padding: '1.2rem 2.2rem'
    }}>
      <div className="container-fluid">
        <div className="d-flex justify-content-between align-items-center">
          <div className="d-flex align-items-center">
            <Link to="/dashboard" className="me-5">
              <img 
                src="/Logo/Sparkle RFID svg.svg" 
                alt="Sparkle RFID" 
                style={{ 
                  height: '48px',
                  transition: 'transform 0.3s ease'
                }}
                onMouseOver={(e) => e.currentTarget.style.transform = 'scale(1.05)'}
                onMouseOut={(e) => e.currentTarget.style.transform = 'scale(1)'}
              />
            </Link>

            <nav className="d-flex align-items-center gap-4">
              {navItems.map((item) => (
                <Link
                  key={item.to}
                  to={item.to}
                  className="text-decoration-none"
                  style={{
                    color: '#333',
                    padding: '0.5rem 1rem',
                    borderRadius: '8px',
                    transition: 'all 0.3s ease',
                    fontSize: '0.95rem',
                    fontWeight: 500
                  }}
                  onMouseOver={(e) => {
                    e.currentTarget.style.background = item.gradient;
                    e.currentTarget.style.color = '#fff';
                    e.currentTarget.style.transform = 'translateY(-2px)';
                  }}
                  onMouseOut={(e) => {
                    e.currentTarget.style.background = 'transparent';
                    e.currentTarget.style.color = '#333';
                    e.currentTarget.style.transform = 'translateY(0)';
                  }}
                >
                  <div className="d-flex align-items-center">
                    {item.icon}
                    {item.text}
                  </div>
                </Link>
              ))}
            </nav>
          </div>

          <div className="d-flex align-items-center">
            {userInfo && (
              <>
                <div className="me-4" style={{ 
                  padding: '0.5rem 1rem',
                  background: 'linear-gradient(135deg, rgba(74, 0, 224, 0.1), rgba(142, 45, 226, 0.1))',
                  borderRadius: '8px',
                  color: '#4A00E0',
                  fontSize: '0.9rem',
                  fontWeight: 500
                }}>
                  Client Code: {userInfo.ClientCode}
                </div>
                <button
                  onClick={handleLogout}
                  className="btn d-flex align-items-center"
                  style={{
                    background: 'transparent',
                    border: '1.5px solid #e0e6ed',
                    borderRadius: '8px',
                    padding: '0.5rem 1rem',
                    color: '#333',
                    transition: 'all 0.3s ease'
                  }}
                  onMouseOver={(e) => {
                    e.currentTarget.style.background = 'linear-gradient(135deg, #ff6b6b, #ff8787)';
                    e.currentTarget.style.color = '#fff';
                    e.currentTarget.style.borderColor = 'transparent';
                  }}
                  onMouseOut={(e) => {
                    e.currentTarget.style.background = 'transparent';
                    e.currentTarget.style.color = '#333';
                    e.currentTarget.style.borderColor = '#e0e6ed';
                  }}
                >
                  <FaSignOutAlt className="me-2" />
                  Logout
                </button>
              </>
            )}
          </div>
        </div>
      </div>
    </header>
  );
};

export default Header;
